fn extract(args: &[magnus::Value]) -> Result<ExtractionResult, Error> {
    let args = magnus::scan_args::scan_args::<(magnus::Value,), (Option<magnus::Value>,), (), (), (), ()>(args)?;
    let (input,) = args.required;

    let (config,) = args.optional;

    let input_core: xberg::ExtractInput = {
        let binding_val: ExtractInput = ExtractInput::try_convert(input).map_err(|e| {
            magnus::Error::new(
                unsafe { Ruby::get_unchecked() }.exception_runtime_error(),
                e.to_string(),
            )
        })?;
        binding_val.into()
    };
    let config_core: xberg::ExtractionConfig = match config {
        Some(_v) if !_v.is_nil() => {
            let binding_val: ExtractionConfig = ExtractionConfig::try_convert(_v).map_err(|e| {
                magnus::Error::new(
                    unsafe { Ruby::get_unchecked() }.exception_runtime_error(),
                    e.to_string(),
                )
            })?;
            binding_val.into()
        }
        _ => Default::default(),
    };
    let rt = tokio::runtime::Runtime::new().map_err(|e| {
        magnus::Error::new(
            unsafe { Ruby::get_unchecked() }.exception_runtime_error(),
            e.to_string(),
        )
    })?;
    let result = rt
        .block_on(async { xberg::extract(input_core, &config_core).await })
        .map_err(|e| {
            magnus::Error::new(
                unsafe { Ruby::get_unchecked() }.exception_runtime_error(),
                e.to_string(),
            )
        })?;
    Ok(result.into())
}

