#[async_trait::async_trait]
impl xberg::EmbeddingBackend for RbEmbeddingBackendBridge {
    fn dimensions(&self) -> usize {
        // SAFETY: bridge methods are only invoked from threads holding the GVL
        let ruby = unsafe { magnus::Ruby::get_unchecked() };
        let value = self.inner.get_inner_with(&ruby);
        let val: magnus::Value = match value.funcall::<_, _, magnus::Value>("dimensions", ()) {
            Ok(v) => v,
            Err(e) => {
                // This method's Rust signature is infallible, so a Ruby exception cannot
                // propagate. Log before substituting the default — a silent default is
                // indistinguishable from a real result to the caller.
                eprintln!("[RbEmbeddingBackendBridge] host 'dimensions' raised; returning default: {e}");
                return Default::default();
            }
        };
        <usize as magnus::TryConvert>::try_convert(val).unwrap_or_else(|e| {
            eprintln!(
                "[RbEmbeddingBackendBridge] host 'dimensions' returned an unconvertible value; returning default: {e}"
            );
            Default::default()
        })
    }

    async fn embed(&self, texts: Vec<String>) -> std::result::Result<Vec<Vec<f32>>, xberg::XbergError> {
        let inner = self.inner;
        let cached_name = self.cached_name.clone();
        let cached_name_for_blocking = cached_name.clone();

        let inner = self.inner;
        let cached_name = self.cached_name.clone();
        // cached_name is referenced both inside the spawn_blocking closure and after
        // the await for the JoinError fallback, so clone once for each consumer.
        let cached_name_for_blocking = cached_name.clone();
        let texts_owned = texts.clone();

        let join: std::result::Result<std::result::Result<Vec<Vec<f32>>, xberg::XbergError>, tokio::task::JoinError> =
            tokio::task::spawn_blocking(move || -> std::result::Result<Vec<Vec<f32>>, xberg::XbergError> {
                // SAFETY: spawn_blocking thread acquires GVL via Ruby::get_unchecked
                let ruby = unsafe { magnus::Ruby::get_unchecked() };
                let value = inner.get_inner_with(&ruby);
                let val: magnus::Value = match value.funcall::<_, _, magnus::Value>(
                    "embed",
                    ({
                        let ruby = unsafe { magnus::Ruby::get_unchecked() };
                        serde_json::to_string(&texts_owned)
                            .ok()
                            .map(|s| ruby.str_new(s.as_str()).as_value())
                            .unwrap_or_else(|| ruby.qnil().as_value())
                    },),
                ) {
                    Ok(v) => v,
                    Err(e) => {
                        return Err(xberg::XbergError::Other(format!(
                            "Plugin '{}' method 'embed' failed: {}",
                            cached_name_for_blocking, e
                        )));
                    }
                };
                <Vec<Vec<f32>> as magnus::TryConvert>::try_convert(val).map_err(|e| {
                    xberg::XbergError::Other(format!("Failed to convert Ruby 'embed' return value: {}", e))
                })
            })
            .await;

        match join {
            Ok(v) => v,
            Err(e) => Err(xberg::XbergError::Other(format!(
                "spawn_blocking failed for '{}': {}",
                cached_name, e
            ))),
        }
    }
}

