impl From<NodeContent> for xberg::NodeContent {
    fn from(val: NodeContent) -> Self {
        match val {
            NodeContent::Title { text } => Self::Title { text: text },
            NodeContent::Heading { level, text } => Self::Heading {
                level: level,
                text: text,
            },
            NodeContent::Paragraph { text } => Self::Paragraph { text: text },
            NodeContent::List { ordered } => Self::List { ordered: ordered },
            NodeContent::ListItem { text } => Self::ListItem { text: text },
            NodeContent::Table { grid } => Self::Table { grid: grid.into() },
            NodeContent::Image {
                description,
                image_index,
                src,
            } => Self::Image {
                description: description,
                image_index: image_index,
                src: src,
            },
            NodeContent::Code { text, language } => Self::Code {
                text: text,
                language: language,
            },
            NodeContent::Quote => Self::Quote,
            NodeContent::Formula { text } => Self::Formula { text: text },
            NodeContent::Footnote { text } => Self::Footnote { text: text },
            NodeContent::Group {
                label,
                heading_level,
                heading_text,
            } => Self::Group {
                label: label,
                heading_level: heading_level,
                heading_text: heading_text,
            },
            NodeContent::PageBreak => Self::PageBreak,
            NodeContent::Slide { number, title } => Self::Slide {
                number: number,
                title: title,
            },
            NodeContent::DefinitionList => Self::DefinitionList,
            NodeContent::DefinitionItem { term, definition } => Self::DefinitionItem {
                term: term,
                definition: definition,
            },
            NodeContent::Citation { key, text } => Self::Citation { key: key, text: text },
            NodeContent::Admonition { kind, title } => Self::Admonition {
                kind: kind,
                title: title,
            },
            NodeContent::RawBlock { format, content } => Self::RawBlock {
                format: format,
                content: content,
            },
            NodeContent::MetadataBlock { entries } => Self::MetadataBlock {
                entries: entries
                    .iter()
                    .filter_map(|inner| {
                        let mut it = inner.iter().cloned();
                        Some((it.next()?, it.next()?))
                    })
                    .collect(),
            },
        }
    }
}

