/// Convert a `xberg::error::XbergError` error to a Magnus runtime error.
#[allow(dead_code)]
fn xberg_error_to_magnus_err(e: xberg::error::XbergError) -> magnus::Error {
    let msg = e.to_string();
    magnus::Error::new(unsafe { magnus::Ruby::get_unchecked() }.exception_runtime_error(), msg)
}

